import { MapContainer as LeafletMap, TileLayer, Marker, Popup, useMapEvents } from 'react-leaflet';
import L from 'leaflet';
import { useEffect, useState } from 'react';

// Pre-define icons based on categories for leaflet since default icons sometimes break in React
const createCategoryIcon = (color, iconName) => {
    return L.divIcon({
        className: 'custom-leaflet-icon',
        html: `<div style="background-color: ${color}; width: 36px; height: 36px; border-radius: 50%; display: flex; align-items: center; justify-content: center; box-shadow: 0 4px 6px rgba(0,0,0,0.3); border: 2px solid white;">
                <span class="material-symbols-outlined" style="color: white; font-size: 20px;">${iconName}</span>
               </div>`,
        iconSize: [36, 36],
        iconAnchor: [18, 18],
        popupAnchor: [0, -18],
    });
};

const categoryIcons = {
    'Medical Help': createCategoryIcon('#ef4444', 'medical_services'),   // Red
    'Shelter': createCategoryIcon('#3b82f6', 'home_work'),          // Blue
    'Water & Food': createCategoryIcon('#22c55e', 'water_drop'),    // Green
    'Electricity / Generator': createCategoryIcon('#eab308', 'electric_bolt'), // Yellow
    'Transport': createCategoryIcon('#a855f7', 'local_shipping'),   // Purple
    'Volunteers': createCategoryIcon('#f97316', 'group'),           // Orange
};

const defaultIcon = createCategoryIcon('#64748b', 'place'); // Slate fallback

// Helper component to track map movements and fetch data inside Bounding Box
const MapBoundsTracker = ({ onBoundsChange }) => {
    const map = useMapEvents({
        moveend: () => {
            const bounds = map.getBounds();
            onBoundsChange({
                minLat: bounds.getSouthWest().lat,
                maxLat: bounds.getNorthEast().lat,
                minLng: bounds.getSouthWest().lng,
                maxLng: bounds.getNorthEast().lng
            });
        }
    });

    // Fire once on mount
    useEffect(() => {
        const bounds = map.getBounds();
        onBoundsChange({
            minLat: bounds.getSouthWest().lat,
            maxLat: bounds.getNorthEast().lat,
            minLng: bounds.getSouthWest().lng,
            maxLng: bounds.getNorthEast().lng
        });
    }, [map, onBoundsChange]);

    return null;
};

export default function MapContainer({ resources = [], onBoundsChange, center = [13.0033, 80.2555], zoom = 14 }) {
    return (
        <div className="w-full h-full relative z-0">
            <LeafletMap
                center={center}
                zoom={zoom}
                className="w-full h-full"
                scrollWheelZoom={true}
                zoomControl={false} // We will use custom zoom controls if needed or keep default out of the way
            >
                <TileLayer
                    url="https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png"
                    attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors &copy; <a href="https://carto.com/attributions">CARTO</a>'
                    maxZoom={20}
                />

                {onBoundsChange && <MapBoundsTracker onBoundsChange={onBoundsChange} />}

                {resources.map((res) => {
                    // Only render if we actually have geographic coordinates
                    if (!res.location_lat || !res.location_lng) return null;

                    const icon = categoryIcons[res.category] || defaultIcon;

                    return (
                        <Marker
                            key={res.id}
                            position={[res.location_lat, res.location_lng]}
                            icon={icon}
                        >
                            <Popup className="custom-popup">
                                <div className="p-1 min-w-[200px]">
                                    <div className="flex items-center gap-2 mb-2">
                                        <span className="text-[10px] uppercase font-bold text-slate-500 bg-slate-100 px-2 py-1 rounded">
                                            {res.category}
                                        </span>
                                    </div>
                                    <h3 className="font-bold text-slate-900 mb-1 leading-tight">{res.title}</h3>
                                    <p className="text-xs text-slate-500 mb-2 line-clamp-2">{res.description}</p>
                                    <a
                                        href={`/resource/${res.id}`}
                                        className="text-xs font-bold text-primary hover:underline"
                                    >
                                        View details &rarr;
                                    </a>
                                </div>
                            </Popup>
                        </Marker>
                    );
                })}
            </LeafletMap>
        </div>
    );
}

import { Link, useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';

export default function Navbar({ user, emergencyMode, onLogout }) {
    const navigate = useNavigate();

    const handleLogout = () => {
        if (onLogout) onLogout();
        navigate('/');
    };

    return (
        <header className="h-20 bg-white/80 backdrop-blur-md border-b border-slate-200 flex items-center justify-between px-8 sticky top-0 z-10">
            {/* Left: Location + Emergency Toggle */}
            <div className="flex items-center gap-6">
                <motion.div
                    whileHover={{ scale: 1.02, backgroundColor: '#f1f5f9' }}
                    className="flex items-center gap-2.5 px-3 py-1.5 rounded-lg cursor-pointer transition-colors"
                >
                    <span className="material-symbols-outlined text-primary">location_on</span>
                    <span className="font-bold text-slate-900">{user?.area_code || 'CHN-ADY-01'}</span>
                </motion.div>
                <div className="h-6 w-px bg-slate-200"></div>
                <div className="flex items-center gap-3">
                    <span className="text-sm font-bold text-slate-500">System Status</span>
                    <motion.div
                        whileHover={{ scale: 1.05 }}
                        className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-xs font-black tracking-widest uppercase shadow-sm ${emergencyMode
                            ? 'bg-rose-500 text-white emergency-pulse shadow-rose-500/20'
                            : 'bg-emerald-50 text-emerald-600 border border-emerald-100'
                            }`}
                    >
                        {emergencyMode ? (
                            <>
                                <span className="material-symbols-outlined text-[16px]">emergency</span>
                                Emergency Active
                            </>
                        ) : (
                            <>
                                <span className="material-symbols-outlined text-[16px]">check_circle</span>
                                Normal
                            </>
                        )}
                    </motion.div>
                </div>
            </div>

            {/* Right: Search + Notifications + Profile */}
            <div className="flex items-center gap-5">
                {/* Search */}
                <div className="relative group">
                    <input
                        className="bg-slate-100 border border-transparent rounded-xl py-2.5 pl-11 pr-4 text-sm w-64 focus:bg-white focus:border-slate-300 focus:ring-4 focus:ring-primary/10 transition-all font-medium"
                        placeholder="Search resources, users..."
                        type="text"
                    />
                    <span className="material-symbols-outlined absolute left-3.5 top-1/2 -translate-y-1/2 text-slate-400 text-sm group-focus-within:text-primary transition-colors">search</span>
                </div>

                {/* Notifications */}
                <motion.button
                    whileHover={{ scale: 1.05, backgroundColor: '#f1f5f9' }}
                    whileTap={{ scale: 0.95 }}
                    className="p-2.5 text-slate-500 rounded-xl relative transition-colors"
                >
                    <span className="material-symbols-outlined">notifications</span>
                    <span className="absolute top-2.5 right-2.5 size-2 bg-rose-500 rounded-full border-2 border-white"></span>
                </motion.button>

                {/* Logout */}
                <motion.button
                    onClick={handleLogout}
                    whileHover={{ scale: 1.05, backgroundColor: '#fff1f2', color: '#e11d48' }}
                    whileTap={{ scale: 0.95 }}
                    className="p-2.5 text-slate-400 rounded-xl transition-colors"
                    title="Logout"
                >
                    <span className="material-symbols-outlined">logout</span>
                </motion.button>

                <div className="h-6 w-px bg-slate-200"></div>

                {/* Profile */}
                <Link to="/profile">
                    <motion.div
                        whileHover={{ scale: 1.02, backgroundColor: '#f8fafc' }}
                        className="flex items-center gap-3 p-1.5 pr-4 rounded-full border border-slate-200 transition-colors cursor-pointer bg-white shadow-sm"
                    >
                        <div className="size-9 rounded-full bg-gradient-to-tr from-primary to-blue-400 flex items-center justify-center text-white text-sm font-black shadow-inner">
                            {user?.name?.charAt(0) || 'U'}
                        </div>
                        <div className="text-left hidden sm:block">
                            <p className="text-sm font-bold text-slate-900 leading-tight">{user?.name || 'User'}</p>
                            <p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">{user?.role || 'Resident'}</p>
                        </div>
                    </motion.div>
                </Link>
            </div>
        </header>
    );
}

import { motion, AnimatePresence } from 'framer-motion';
import { useLocation } from 'react-router-dom';
import useReducedMotion from '../hooks/useReducedMotion';

/**
 * PageTransition — Wraps page content with enter/exit animations.
 * Use inside <Routes> or as a wrapper around page content.
 *
 * @param {Object} props
 * @param {React.ReactNode} props.children
 * @param {string} props.className
 */
export default function PageTransition({ children, className = '' }) {
    const location = useLocation();
    const prefersReduced = useReducedMotion();

    if (prefersReduced) {
        return <div className={className}>{children}</div>;
    }

    return (
        <AnimatePresence mode="wait">
            <motion.div
                key={location.pathname}
                initial={{ opacity: 0, y: 12 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -8 }}
                transition={{
                    duration: 0.45,
                    ease: [0.25, 0.46, 0.45, 0.94],
                }}
                className={className}
            >
                {children}
            </motion.div>
        </AnimatePresence>
    );
}

import { useRef } from 'react';
import { motion, useScroll, useTransform } from 'framer-motion';
import useReducedMotion from '../hooks/useReducedMotion';

/**
 * ParallaxSection — Subtle parallax scrolling effect.
 * Uses Framer Motion's useScroll + useTransform for GPU-accelerated transforms.
 *
 * @param {Object} props
 * @param {React.ReactNode} props.children
 * @param {number} props.speed - Parallax intensity. Positive = slower, negative = faster (default: 0.3)
 * @param {string} props.className - Additional classes
 * @param {'y' | 'x'} props.direction - Parallax direction (default: 'y')
 */
export default function ParallaxSection({
    children,
    speed = 0.3,
    className = '',
    direction = 'y',
    ...rest
}) {
    const ref = useRef(null);
    const prefersReduced = useReducedMotion();

    const { scrollYProgress } = useScroll({
        target: ref,
        offset: ['start end', 'end start'],
    });

    const range = 100 * speed;
    const yValue = useTransform(scrollYProgress, [0, 1], [range, -range]);
    const xValue = useTransform(scrollYProgress, [0, 1], [range, -range]);

    if (prefersReduced) {
        return (
            <div ref={ref} className={className} {...rest}>
                {children}
            </div>
        );
    }

    return (
        <div ref={ref} className={`overflow-hidden ${className}`} {...rest}>
            <motion.div
                style={direction === 'y' ? { y: yValue } : { x: xValue }}
                className="will-change-transform"
            >
                {children}
            </motion.div>
        </div>
    );
}

import { motion, useInView } from 'framer-motion';
import { useRef } from 'react';
import useReducedMotion from '../hooks/useReducedMotion';

/**
 * Reveal — Scroll-triggered scale + fade animation.
 * Subtler than FadeUp, great for cards and content blocks.
 *
 * @param {Object} props
 * @param {React.ReactNode} props.children
 * @param {number} props.delay - Delay in seconds (default: 0)
 * @param {number} props.duration - Duration in seconds (default: 0.7)
 * @param {boolean} props.once - Trigger once (default: true)
 * @param {string} props.direction - 'up' | 'down' | 'left' | 'right' | 'scale' (default: 'up')
 * @param {string} props.className - Additional classes
 */
export default function Reveal({
    children,
    delay = 0,
    duration = 0.7,
    once = true,
    direction = 'up',
    className = '',
    ...rest
}) {
    const ref = useRef(null);
    const isInView = useInView(ref, { once, margin: '-40px 0px' });
    const prefersReduced = useReducedMotion();

    const directionMap = {
        up: { y: 24, x: 0, scale: 1 },
        down: { y: -24, x: 0, scale: 1 },
        left: { y: 0, x: -40, scale: 1 },
        right: { y: 0, x: 40, scale: 1 },
        scale: { y: 0, x: 0, scale: 0.95 },
    };

    const dir = directionMap[direction] || directionMap.up;

    return (
        <motion.div
            ref={ref}
            initial={prefersReduced
                ? { opacity: 1 }
                : { opacity: 0, y: dir.y, x: dir.x, scale: dir.scale }
            }
            animate={isInView
                ? { opacity: 1, y: 0, x: 0, scale: 1 }
                : prefersReduced
                    ? { opacity: 1 }
                    : { opacity: 0, y: dir.y, x: dir.x, scale: dir.scale }
            }
            transition={{
                duration: prefersReduced ? 0 : duration,
                delay: prefersReduced ? 0 : delay,
                ease: [0.16, 1, 0.3, 1],
            }}
            className={className}
            {...rest}
        >
            {children}
        </motion.div>
    );
}

import { motion, useScroll, useSpring } from 'framer-motion';
import useReducedMotion from '../hooks/useReducedMotion';

/**
 * ScrollProgressBar — Thin progress indicator at the top of the viewport.
 * Shows page scroll percentage with a spring-damped animation.
 *
 * @param {Object} props
 * @param {string} props.color - Bar color (default: Tailwind primary)
 * @param {number} props.height - Bar height in px (default: 3)
 */
export default function ScrollProgressBar({
    color = '#308ce8',
    height = 3,
}) {
    const prefersReduced = useReducedMotion();
    const { scrollYProgress } = useScroll();

    const scaleX = useSpring(scrollYProgress, {
        stiffness: 100,
        damping: 30,
        restDelta: 0.001,
    });

    if (prefersReduced) return null;

    return (
        <motion.div
            style={{
                scaleX,
                transformOrigin: '0%',
                background: color,
                height: `${height}px`,
            }}
            className="fixed top-0 left-0 right-0 z-[9999]"
        />
    );
}

import { Link, useLocation } from 'react-router-dom';
import { motion } from 'framer-motion';

const menuItems = [
    { path: '/dashboard', label: 'Home', icon: 'home' },
    { path: '/map', label: 'Resource Map', icon: 'map' },
    { path: '/post-resource', label: 'Post Resource', icon: 'add_box' },
    { path: '/request-resource', label: 'Requests', icon: 'volunteer_activism' },
    { path: '/emergency', label: 'Emergency Mode', icon: 'emergency' },
    { path: '/volunteers', label: 'Volunteers', icon: 'groups' },
    { path: '/alerts', label: 'Community Alerts', icon: 'notifications_active' },
];

const adminItem = { path: '/admin', label: 'Admin Control', icon: 'shield_with_heart' };

export default function Sidebar({ isAdmin }) {
    const location = useLocation();
    const items = isAdmin ? [...menuItems, adminItem] : menuItems;

    return (
        <aside className="w-72 bg-white border-r border-slate-200 flex flex-col fixed h-screen z-20 shadow-[4px_0_24px_rgba(0,0,0,0.02)]">
            {/* Brand */}
            <div className="p-6 flex items-center gap-3">
                <motion.div
                    whileHover={{ rotate: [0, -5, 5, 0], scale: 1.05 }}
                    transition={{ duration: 0.4 }}
                    className="size-10 rounded-xl bg-primary flex items-center justify-center text-white shadow-md shadow-primary/20"
                >
                    <span className="material-symbols-outlined">diversity_3</span>
                </motion.div>
                <div>
                    <h1 className="text-lg font-black tracking-tight leading-none text-slate-900">Namma Thunai</h1>
                    <p className="text-[11px] font-bold uppercase tracking-widest text-slate-400 mt-1">Community Support</p>
                </div>
            </div>

            {/* Navigation */}
            <nav className="flex-1 px-4 py-2 space-y-1 overflow-y-auto">
                {items.map((item) => {
                    const isActive = location.pathname === item.path;
                    return (
                        <Link
                            key={item.path}
                            to={item.path}
                            className={`flex items-center gap-3 px-4 py-3 rounded-xl font-semibold transition-all group relative overflow-hidden ${isActive
                                ? 'text-primary'
                                : 'text-slate-600 hover:text-slate-900 hover:bg-slate-50'
                                }`}
                        >
                            {isActive && (
                                <motion.div
                                    layoutId="active-nav-bg"
                                    className="absolute inset-0 bg-primary/10 border-l-4 border-primary"
                                    initial={false}
                                    transition={{ type: 'spring', stiffness: 300, damping: 30 }}
                                />
                            )}
                            <span className={`material-symbols-outlined relative z-10 transition-transform duration-300 group-hover:scale-110 ${isActive ? 'filled' : ''}`}>
                                {item.icon}
                            </span>
                            <span className="text-sm relative z-10">{item.label}</span>
                        </Link>
                    );
                })}
            </nav>

            {/* Profile Link */}
            <div className="p-4 border-t border-slate-100">
                <Link
                    to="/profile"
                    className={`flex items-center gap-3 px-4 py-3 rounded-xl font-semibold transition-all group relative overflow-hidden ${location.pathname === '/profile'
                        ? 'text-primary'
                        : 'text-slate-600 hover:text-slate-900 hover:bg-slate-50'
                        }`}
                >
                    {location.pathname === '/profile' && (
                        <motion.div
                            layoutId="active-nav-bg"
                            className="absolute inset-0 bg-primary/10 border-l-4 border-primary"
                            initial={false}
                            transition={{ type: 'spring', stiffness: 300, damping: 30 }}
                        />
                    )}
                    <span className={`material-symbols-outlined relative z-10 transition-transform duration-300 group-hover:scale-110 ${location.pathname === '/profile' ? 'filled' : ''}`}>
                        account_circle
                    </span>
                    <span className="text-sm relative z-10">Profile Settings</span>
                </Link>
            </div>
        </aside>
    );
}

import { motion, useInView } from 'framer-motion';
import { useRef } from 'react';
import useReducedMotion from '../hooks/useReducedMotion';

/**
 * StaggerContainer — Animates children with staggered delays.
 * Pairs with StaggerItem for a coordinated entrance effect.
 *
 * @param {Object} props
 * @param {React.ReactNode} props.children
 * @param {number} props.staggerDelay - Delay between children in seconds (default: 0.1)
 * @param {number} props.startDelay - Delay before first child (default: 0.1)
 * @param {boolean} props.once - Trigger once (default: true)
 * @param {string} props.className - Additional classes
 */
export function StaggerContainer({
    children,
    staggerDelay = 0.1,
    startDelay = 0.1,
    once = true,
    className = '',
    ...rest
}) {
    const ref = useRef(null);
    const isInView = useInView(ref, { once, margin: '-40px 0px' });
    const prefersReduced = useReducedMotion();

    return (
        <motion.div
            ref={ref}
            initial="hidden"
            animate={isInView ? 'visible' : 'hidden'}
            variants={{
                hidden: {},
                visible: {
                    transition: {
                        staggerChildren: prefersReduced ? 0 : staggerDelay,
                        delayChildren: prefersReduced ? 0 : startDelay,
                    },
                },
            }}
            className={className}
            {...rest}
        >
            {children}
        </motion.div>
    );
}

/**
 * StaggerItem — Individual child inside a StaggerContainer.
 * Animates with fade + translate-y.
 *
 * @param {Object} props
 * @param {React.ReactNode} props.children
 * @param {string} props.className - Additional classes
 * @param {'up' | 'scale'} props.variant - Animation style (default: 'up')
 */
export function StaggerItem({
    children,
    className = '',
    variant = 'up',
    ...rest
}) {
    const prefersReduced = useReducedMotion();

    const variants = {
        up: {
            hidden: prefersReduced ? { opacity: 1 } : { opacity: 0, y: 24 },
            visible: {
                opacity: 1,
                y: 0,
                transition: {
                    duration: 0.5,
                    ease: [0.25, 0.46, 0.45, 0.94],
                },
            },
        },
        scale: {
            hidden: prefersReduced ? { opacity: 1 } : { opacity: 0, scale: 0.95 },
            visible: {
                opacity: 1,
                scale: 1,
                transition: {
                    duration: 0.5,
                    ease: [0.25, 0.46, 0.45, 0.94],
                },
            },
        },
    };

    return (
        <motion.div
            variants={variants[variant] || variants.up}
            className={className}
            {...rest}
        >
            {children}
        </motion.div>
    );
}

import { createContext, useContext, useState } from 'react';
import { authService } from '../services/api';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
    const [user, setUser] = useState(null);
    const [emergencyMode, setEmergencyMode] = useState(false);

    const login = async (credentials) => {
        const res = await authService.login(credentials);
        setUser(res.data.user);
        return res.data.user;
    };

    const logout = () => {
        setUser(null);
    };

    const value = {
        user,
        setUser,
        login,
        logout,
        emergencyMode,
        setEmergencyMode
    };

    return (
        <AuthContext.Provider value={value}>
            {children}
        </AuthContext.Provider>
    );
}

export function useAuth() {
    const context = useContext(AuthContext);
    if (!context) {
        throw new Error('useAuth must be used within an AuthProvider');
    }
    return context;
}

export default AuthContext;

