import { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth';
import { alertService } from '../services/api';
import { timeAgo } from '../utils/helpers';
import { motion, AnimatePresence } from 'framer-motion';
import FadeUp from '../components/AnimatedSection';
import { StaggerContainer, StaggerItem } from '../components/StaggerContainer';
import Reveal from '../components/Reveal';

export default function CommunityAlerts() {
    const { user } = useAuth();
    const [alerts, setAlerts] = useState([]);
    const [showForm, setShowForm] = useState(false);
    const [formData, setFormData] = useState({ alert_type: 'Info', message: '' });

    const fetchAlerts = async () => {
        try {
            const res = await alertService.getAll();
            setAlerts(res.data);
        } catch (err) {
            console.error("Failed to fetch alerts", err);
            // Fallback mock data
            setAlerts([
                { id: 1, alert_type: 'Warning', message: 'Flooding expected in low-lying areas of Adyar. Move valuables to higher ground.', is_active: true, admin_name: 'Admin', created_at: new Date(Date.now() - 3600000).toISOString() },
                { id: 2, alert_type: 'Info', message: 'Municipal water tankers dispatched to T. Nagar. Expected arrival: 4 PM.', is_active: true, admin_name: 'Admin', created_at: new Date(Date.now() - 7200000).toISOString() },
                { id: 3, alert_type: 'Resolved', message: 'Power restored in Mylapore sector. All residents can return to normal operations.', is_active: false, admin_name: 'Admin', created_at: new Date(Date.now() - 18000000).toISOString() },
            ]);
        }
    };

    useEffect(() => {
        fetchAlerts();
    }, []);

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            await alertService.create({
                admin_id: user?.id || 1,
                alert_type: formData.alert_type,
                message: formData.message
            });
            setFormData({ alert_type: 'Info', message: '' });
            setShowForm(false);
            fetchAlerts();
        } catch (err) {
            console.error("Failed to post alert", err);
        }
    };

    const handleDeactivate = async (id) => {
        try {
            await alertService.deactivate(id);
            fetchAlerts();
        } catch (err) {
            console.error("Failed to deactivate alert", err);
        }
    };

    const getAlertStyle = (type, isActive) => {
        if (!isActive) return { bg: 'bg-slate-50 border-slate-200', icon: 'check_circle', iconColor: 'text-slate-400', textColor: 'text-slate-500', tagBg: 'bg-slate-200 text-slate-600', ring: '' };
        switch (type) {
            case 'Warning': return { bg: 'bg-orange-50 border-orange-200', icon: 'warning', iconColor: 'text-orange-500', textColor: 'text-orange-900', tagBg: 'bg-orange-200 text-orange-800', ring: 'ring-1 ring-orange-500/20' };
            case 'Critical': return { bg: 'bg-rose-50 border-rose-200', icon: 'emergency', iconColor: 'text-rose-500', textColor: 'text-rose-900', tagBg: 'bg-rose-200 text-rose-800', ring: 'ring-1 ring-rose-500/30' };
            case 'Resolved': return { bg: 'bg-emerald-50 border-emerald-200', icon: 'check_circle', iconColor: 'text-emerald-500', textColor: 'text-emerald-900', tagBg: 'bg-emerald-200 text-emerald-800', ring: '' };
            default: return { bg: 'bg-blue-50 border-blue-200', icon: 'info', iconColor: 'text-blue-500', textColor: 'text-blue-900', tagBg: 'bg-blue-200 text-blue-800', ring: '' };
        }
    };

    return (
        <div className="p-6 lg:p-10 max-w-5xl mx-auto">
            {/* Header */}
            <FadeUp>
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-8 pb-6 border-b border-slate-200">
                    <div>
                        <h2 className="text-3xl lg:text-4xl font-black tracking-tight text-slate-900 flex items-center gap-3">
                            <span className="material-symbols-outlined text-primary text-[40px] drop-shadow-sm">notifications_active</span>
                            Community Alerts
                        </h2>
                        <p className="text-slate-500 mt-2 text-lg font-medium">Official updates from area admins and local authorities.</p>
                    </div>
                    {user?.role === 'Admin' && (
                        <motion.button
                            onClick={() => setShowForm(!showForm)}
                            whileHover={{ scale: 1.05 }}
                            whileTap={{ scale: 0.95 }}
                            className={`flex items-center gap-2 font-bold px-6 py-3.5 rounded-2xl shadow-sm transition-colors ${showForm
                                ? 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                                : 'bg-primary text-white shadow-primary/20 hover:bg-primary/90'
                                }`}
                        >
                            <span className="material-symbols-outlined text-lg">{showForm ? 'close' : 'add_alert'}</span>
                            {showForm ? 'Cancel' : 'Post New Alert'}
                        </motion.button>
                    )}
                </div>
            </FadeUp>

            {/* Admin Alert Form */}
            <AnimatePresence>
                {showForm && (
                    <motion.form
                        initial={{ opacity: 0, height: 0, overflow: 'hidden' }}
                        animate={{ opacity: 1, height: 'auto', overflow: 'visible' }}
                        exit={{ opacity: 0, height: 0, overflow: 'hidden' }}
                        transition={{ duration: 0.4, ease: [0.25, 0.46, 0.45, 0.94] }}
                        onSubmit={handleSubmit}
                        className="bg-white p-8 lg:p-10 rounded-3xl border border-slate-200 shadow-xl shadow-slate-200/50 mb-10 space-y-6 relative"
                    >
                        <div className="absolute top-0 right-0 w-32 h-32 bg-primary/5 rounded-full blur-3xl -mx-10 -my-10"></div>
                        <h3 className="font-black text-2xl text-slate-900 tracking-tight">New Community Alert</h3>
                        <div className="space-y-3 relative z-10">
                            <label className="text-sm font-black uppercase tracking-widest text-slate-600">Alert Type</label>
                            <div className="relative group">
                                <select
                                    value={formData.alert_type}
                                    onChange={(e) => setFormData({ ...formData, alert_type: e.target.value })}
                                    className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-5 py-4 text-base font-semibold focus:bg-white focus:border-primary focus:ring-4 focus:ring-primary/10 transition-all appearance-none cursor-pointer"
                                >
                                    <option value="Info" className="font-semibold">Info - General Information</option>
                                    <option value="Warning" className="font-semibold">Warning - Potential Hazard</option>
                                    <option value="Critical" className="font-semibold text-rose-600">Critical - Immediate Danger</option>
                                    <option value="Resolved" className="font-semibold text-emerald-600">Resolved - All Clear</option>
                                </select>
                                <span className="material-symbols-outlined absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none group-focus-within:text-primary transition-colors">expand_more</span>
                            </div>
                        </div>
                        <div className="space-y-3 relative z-10">
                            <label className="text-sm font-black uppercase tracking-widest text-slate-600 flex items-center justify-between">
                                Message Body
                                <span className="text-rose-500 font-bold">*</span>
                            </label>
                            <textarea
                                rows="4"
                                placeholder="Write a clear, actionable message for the community. Include specific details like locations and timeframes."
                                value={formData.message}
                                onChange={(e) => setFormData({ ...formData, message: e.target.value })}
                                className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-5 py-4 text-base font-medium focus:bg-white focus:border-primary focus:ring-4 focus:ring-primary/10 transition-all resize-none shadow-inner"
                                required
                            />
                        </div>
                        <div className="pt-2 relative z-10">
                            <motion.button
                                whileHover={{ scale: 1.02 }}
                                whileTap={{ scale: 0.98 }}
                                type="submit"
                                className="flex items-center justify-center gap-2 w-full sm:w-auto bg-primary text-white font-bold px-10 py-4 rounded-2xl shadow-lg shadow-primary/20 hover:bg-primary/90 transition-colors"
                            >
                                <span className="material-symbols-outlined text-lg">campaign</span>
                                Publish Global Alert
                            </motion.button>
                        </div>
                    </motion.form>
                )}
            </AnimatePresence>

            {/* Alerts Timeline */}
            <Reveal delay={0.2} direction="up">
                <div className="space-y-6">
                    {alerts.length > 0 ? (
                        <StaggerContainer staggerDelay={0.15}>
                            {alerts.map(alert => {
                                const style = getAlertStyle(alert.alert_type, alert.is_active);
                                return (
                                    <StaggerItem key={alert.id} variant="scale">
                                        <motion.div
                                            whileHover={{ y: -4, boxShadow: '0 20px 40px -10px rgba(0,0,0,0.05)' }}
                                            className={`p-6 lg:p-8 rounded-3xl border-2 ${style.bg} ${style.border} ${style.ring} flex flex-col sm:flex-row items-start gap-6 transition-all ${!alert.is_active ? 'opacity-70 saturate-[0.8]' : ''}`}
                                        >
                                            <div className="flex-shrink-0 bg-white p-3.5 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-center relative">
                                                {alert.alert_type === 'Critical' && alert.is_active && (
                                                    <span className="absolute inset-0 rounded-2xl blur-md bg-rose-500/30 animate-pulse"></span>
                                                )}
                                                <span className={`material-symbols-outlined text-3xl relative z-10 ${style.iconColor}`}>{style.icon}</span>
                                            </div>
                                            <div className="flex-1 w-full relative">
                                                <div className="flex flex-wrap items-center gap-3 mb-3">
                                                    <span className={`text-[11px] font-black px-3 py-1.5 rounded-lg ${style.tagBg} uppercase tracking-widest leading-none`}>
                                                        {alert.alert_type}
                                                    </span>
                                                    <span className="text-sm text-slate-500 font-semibold">{timeAgo(alert.created_at)}</span>
                                                    {!alert.is_active && <span className="text-[11px] font-black uppercase tracking-widest text-slate-500 bg-slate-200 px-3 py-1.5 rounded-lg leading-none border border-slate-300">Resolved</span>}
                                                </div>
                                                <p className={`text-xl lg:text-2xl font-semibold leading-relaxed tracking-tight ${style.textColor}`}>{alert.message}</p>
                                                <div className="mt-5 flex items-center gap-2">
                                                    <div className="w-6 h-6 rounded-full bg-slate-200 flex items-center justify-center border border-slate-300">
                                                        <span className="material-symbols-outlined text-[12px] text-slate-500">shield_person</span>
                                                    </div>
                                                    <span className="text-sm text-slate-500 font-semibold">Posted by <span className="text-slate-700">{alert.admin_name || 'Area Admin'}</span></span>
                                                </div>
                                            </div>
                                            {alert.is_active && user?.role === 'Admin' && (
                                                <motion.button
                                                    whileHover={{ scale: 1.05 }}
                                                    whileTap={{ scale: 0.95 }}
                                                    onClick={() => handleDeactivate(alert.id)}
                                                    className="w-full sm:w-auto text-sm font-bold text-slate-500 hover:text-emerald-700 transition-colors bg-white px-5 py-3 rounded-2xl border-2 border-slate-200 hover:border-emerald-200 hover:bg-emerald-50 flex-shrink-0 flex items-center justify-center gap-2 shadow-sm"
                                                >
                                                    <span className="material-symbols-outlined text-lg">check_circle</span>
                                                    Mark Resolved
                                                </motion.button>
                                            )}
                                        </motion.div>
                                    </StaggerItem>
                                );
                            })}
                        </StaggerContainer>
                    ) : (
                        <div className="bg-white rounded-3xl p-16 text-center border-2 border-dashed border-slate-200">
                            <div className="w-24 h-24 mx-auto mb-6 bg-slate-50 rounded-full flex items-center justify-center">
                                <span className="material-symbols-outlined text-[60px] text-slate-300">notifications_off</span>
                            </div>
                            <h3 className="font-black text-slate-800 text-2xl mb-2">No Active Alerts</h3>
                            <p className="text-slate-500 font-medium text-lg">Your neighborhood is currently clear. Area admins will post important updates here when necessary.</p>
                        </div>
                    )}
                </div>
            </Reveal>
        </div>
    );
}

import { useParams, useNavigate } from 'react-router-dom';
import { useState, useEffect } from 'react';
import { useAuth } from '../hooks/useAuth';
import { resourceService, requestService } from '../services/api';
import { motion } from 'framer-motion';
import FadeUp from '../components/AnimatedSection';
import Reveal from '../components/Reveal';
import { StaggerContainer, StaggerItem } from '../components/StaggerContainer';

export default function ResourceDetail() {
    const { user } = useAuth();
    const { id } = useParams();
    const navigate = useNavigate();
    const [resource, setResource] = useState(null);
    const [loading, setLoading] = useState(true);
    const [requested, setRequested] = useState(false);

    useEffect(() => {
        const fetchResource = async () => {
            try {
                const res = await resourceService.getById(id);
                setResource(res.data);
            } catch (err) {
                console.error("Failed to fetch resource", err);
            } finally {
                setLoading(false);
            }
        };
        fetchResource();
    }, [id]);

    const handleRequest = async () => {
        try {
            await requestService.create({
                user_id: user?.id || 1,
                category: resource.category,
                description: `Requesting: ${resource.title}`,
                urgency_level: resource.is_emergency ? 'Critical' : 'Essential'
            });
            setRequested(true);
        } catch (err) {
            console.error("Failed to send request", err);
        }
    };

    if (loading) {
        return (
            <div className="p-8 flex items-center justify-center min-h-[60vh]">
                <motion.div
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    className="text-center"
                >
                    <div className="w-16 h-16 border-4 border-primary/20 border-t-primary rounded-full animate-spin mx-auto mb-6"></div>
                    <p className="text-slate-500 font-bold text-lg tracking-wide">Loading resource details...</p>
                </motion.div>
            </div>
        );
    }

    if (!resource) {
        return (
            <div className="p-8 flex items-center justify-center min-h-[60vh]">
                <FadeUp y={20} className="max-w-md w-full">
                    <div className="text-center bg-white p-12 rounded-3xl border border-slate-200 shadow-lg shadow-slate-200/50 relative overflow-hidden">
                        <div className="absolute top-0 left-0 right-0 h-1.5 bg-rose-500"></div>
                        <span className="material-symbols-outlined text-[80px] text-slate-200 mb-6 block">search_off</span>
                        <h2 className="text-2xl font-black text-slate-900 mb-3 tracking-tight">Resource Not Found</h2>
                        <p className="text-slate-500 font-medium mb-8 leading-relaxed">This resource may have been removed or claimed by another community member.</p>
                        <motion.button
                            onClick={() => navigate('/map')}
                            whileHover={{ scale: 1.04, boxShadow: '0 12px 24px -10px rgba(48, 140, 232, 0.4)' }}
                            whileTap={{ scale: 0.97 }}
                            className="w-full bg-primary text-white font-bold px-6 py-4 rounded-xl transition-all flex items-center justify-center gap-2"
                        >
                            <span className="material-symbols-outlined">map</span>
                            Browse Resource Map
                        </motion.button>
                    </div>
                </FadeUp>
            </div>
        );
    }

    const categoryIcons = {
        'Medical Help': 'medical_services',
        'Shelter': 'home_work',
        'Water & Food': 'water_drop',
        'Electricity / Generator': 'electric_bolt',
        'Transport': 'local_shipping',
        'Volunteers': 'groups',
    };

    const iconName = categoryIcons[resource.category] || 'electric_bolt';

    return (
        <div className="p-6 lg:p-10 max-w-6xl mx-auto">
            {/* Breadcrumb */}
            <FadeUp delay={0.1}>
                <nav className="flex items-center gap-3 text-sm font-semibold text-slate-500 mb-8 bg-white/50 backdrop-blur w-fit px-4 py-2 rounded-full border border-slate-200">
                    <button onClick={() => navigate('/dashboard')} className="hover:text-primary transition-colors hover:scale-105 active:scale-95">Home</button>
                    <span className="material-symbols-outlined text-sm text-slate-300">chevron_right</span>
                    <button onClick={() => navigate('/map')} className="hover:text-primary transition-colors hover:scale-105 active:scale-95">Resources</button>
                    <span className="material-symbols-outlined text-sm text-slate-300">chevron_right</span>
                    <span className="text-slate-900 font-bold truncate max-w-[200px]">{resource.title}</span>
                </nav>
            </FadeUp>

            {/* Main Detail Card */}
            <FadeUp delay={0.2} y={30}>
                <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-200 overflow-hidden relative">
                    <div className="absolute top-0 right-0 w-64 h-64 bg-primary/5 rounded-full blur-3xl -mx-20 -my-20"></div>

                    <div className="p-8 lg:p-10 flex flex-col lg:flex-row gap-10 relative z-10">
                        {/* Image / Icon Area */}
                        <div className="w-full lg:w-1/3">
                            <motion.div
                                whileHover={{ scale: 1.02 }}
                                transition={{ duration: 0.4 }}
                                className="aspect-square rounded-2xl bg-gradient-to-br from-slate-50 to-slate-100/50 border border-slate-100 flex items-center justify-center relative overflow-hidden group shadow-inner"
                            >
                                <div className="absolute inset-0 bg-gradient-to-br from-primary/10 to-transparent"></div>
                                <motion.span
                                    animate={{ y: [0, -6, 0] }}
                                    transition={{ duration: 4, repeat: Infinity, ease: 'easeInOut' }}
                                    className="material-symbols-outlined text-[100px] text-primary/40 group-hover:scale-110 transition-transform duration-500 drop-shadow-md"
                                >
                                    {iconName}
                                </motion.span>
                                <div className="absolute bottom-4 left-4 right-4 bg-white/90 backdrop-blur-md p-3.5 rounded-xl flex items-center justify-between border border-white/50 shadow-sm">
                                    <span className="text-xs font-black uppercase tracking-widest text-slate-600">{resource.category}</span>
                                    <div className="flex items-center gap-1.5 text-emerald-600 bg-emerald-50 px-2 py-1 rounded-md">
                                        <span className="material-symbols-outlined text-[16px] filled">verified</span>
                                        <span className="text-[10px] font-black tracking-widest uppercase">VERIFIED</span>
                                    </div>
                                </div>
                            </motion.div>
                        </div>

                        {/* Details */}
                        <div className="flex-1 flex flex-col pt-2">
                            <div className="flex justify-between items-start mb-4">
                                <h1 className="text-3xl lg:text-5xl font-black text-slate-900 tracking-tight leading-[1.1]">{resource.title}</h1>
                                <motion.button
                                    whileHover={{ scale: 1.1, backgroundColor: '#f1f5f9' }}
                                    whileTap={{ scale: 0.9 }}
                                    className="p-3 text-slate-400 hover:text-primary rounded-xl transition-colors bg-white border border-slate-100 shadow-sm"
                                >
                                    <span className="material-symbols-outlined">share</span>
                                </motion.button>
                            </div>

                            <div className="flex flex-wrap gap-4 items-center mb-8 border-b border-slate-100 pb-8">
                                <div className="flex items-center gap-2 text-slate-600 bg-slate-50 px-3 py-1.5 rounded-lg border border-slate-100 font-semibold">
                                    <span className="material-symbols-outlined text-lg text-primary">location_on</span>
                                    <span className="text-sm">Adyar, Chennai • Nearby</span>
                                </div>
                                <div className="flex items-center gap-2 text-slate-600 bg-slate-50 px-3 py-1.5 rounded-lg border border-slate-100 font-semibold">
                                    <span className="material-symbols-outlined text-lg text-slate-400">schedule</span>
                                    <span className="text-sm">Listed {new Date(resource.created_at).toLocaleString([], { dateStyle: 'medium', timeStyle: 'short' })}</span>
                                </div>
                            </div>

                            {/* Info Cards */}
                            <StaggerContainer staggerDelay={0.15} className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
                                <StaggerItem variant="scale">
                                    <div className="p-5 rounded-2xl border border-primary/20 bg-primary/5 flex items-center gap-4 hover:bg-primary/10 transition-colors">
                                        <div className="w-14 h-14 rounded-xl bg-white shadow-sm flex items-center justify-center text-primary">
                                            <span className="material-symbols-outlined text-3xl font-bold filled">verified_user</span>
                                        </div>
                                        <div>
                                            <p className="text-[11px] font-black text-primary/70 uppercase tracking-widest mb-1">Trust Score</p>
                                            <p className="text-2xl font-black text-slate-900 leading-none">{resource.provider_trust_score || 98}<span className="text-sm font-bold text-slate-500 ml-1">%</span></p>
                                        </div>
                                    </div>
                                </StaggerItem>
                                <StaggerItem variant="scale">
                                    <div className="p-5 rounded-2xl border border-amber-200 bg-amber-50 flex items-center gap-4 hover:bg-amber-100/50 transition-colors">
                                        <div className="w-14 h-14 rounded-xl bg-white shadow-sm flex items-center justify-center text-amber-500 border border-amber-100">
                                            <span className="material-symbols-outlined text-3xl filled">event_available</span>
                                        </div>
                                        <div>
                                            <p className="text-[11px] font-black text-amber-700/70 uppercase tracking-widest mb-1">Availability</p>
                                            <p className="text-lg font-bold text-amber-900 leading-tight">{resource.availability_duration || 'Until claimed'}</p>
                                        </div>
                                    </div>
                                </StaggerItem>
                            </StaggerContainer>

                            {/* Description */}
                            <Reveal delay={0.4}>
                                <div className="space-y-4 mb-10">
                                    <h3 className="text-lg font-black text-slate-900 flex items-center gap-2">
                                        <span className="material-symbols-outlined text-primary">description</span>
                                        Resource Description
                                    </h3>
                                    <p className="text-slate-600 text-lg leading-relaxed font-medium bg-slate-50 p-6 rounded-2xl border border-slate-100">
                                        {resource.description || 'No additional description provided for this resource.'}
                                    </p>
                                </div>
                            </Reveal>

                            {/* Action Buttons */}
                            <Reveal delay={0.5} y={20}>
                                <div className="flex flex-col sm:flex-row gap-4 mt-auto">
                                    {requested ? (
                                        <motion.div
                                            initial={{ scale: 0.95, opacity: 0 }}
                                            animate={{ scale: 1, opacity: 1 }}
                                            className="flex-1 bg-emerald-50 text-emerald-700 font-bold py-4 px-6 rounded-2xl border border-emerald-200 flex items-center justify-center gap-2 shadow-sm"
                                        >
                                            <span className="material-symbols-outlined text-2xl filled">check_circle</span>
                                            Request Sent Successfully
                                        </motion.div>
                                    ) : (
                                        <motion.button
                                            onClick={handleRequest}
                                            disabled={resource.status !== 'Available'}
                                            whileHover={{ scale: resource.status === 'Available' ? 1.03 : 1, boxShadow: resource.status === 'Available' ? '0 12px 30px rgba(48,140,232,0.3)' : 'none' }}
                                            whileTap={{ scale: resource.status === 'Available' ? 0.97 : 1 }}
                                            className={`flex-1 text-lg font-black py-4 px-8 rounded-2xl transition-all flex items-center justify-center gap-3 ${resource.status === 'Available'
                                                ? 'bg-primary text-white shadow-lg'
                                                : 'bg-slate-100 text-slate-400 cursor-not-allowed border border-slate-200'
                                                }`}
                                        >
                                            <span className="material-symbols-outlined text-2xl">{resource.status === 'Available' ? 'handshake' : 'block'}</span>
                                            {resource.status === 'Available' ? 'Request Immediate Help' : 'Resource Unavailable'}
                                        </motion.button>
                                    )}
                                    <div className="relative group flex-1">
                                        <motion.button
                                            whileHover={{ backgroundColor: '#f8fafc', borderColor: '#cbd5e1' }}
                                            className="w-full h-full bg-white text-slate-500 font-bold py-4 px-6 rounded-2xl cursor-not-allowed flex items-center justify-center gap-3 border-2 border-slate-200 transition-colors"
                                        >
                                            <span className="material-symbols-outlined text-xl">chat_bubble</span>
                                            Start Chat
                                        </motion.button>
                                        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-3 w-max opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-20 y-2">
                                            <div className="bg-slate-900 text-white text-xs font-medium py-2.5 px-4 rounded-xl shadow-xl border border-slate-700">
                                                Available after request is accepted
                                                <div className="absolute top-full left-1/2 -translate-x-1/2 border-[6px] border-transparent border-t-slate-900"></div>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </Reveal>
                        </div>
                    </div>

                    {/* Location Map Section */}
                    <div className="border-t border-slate-200 p-8 lg:p-10 bg-slate-50 relative overflow-hidden">
                        <div className="absolute top-0 bottom-0 left-0 w-1.5 bg-gradient-to-b from-primary to-blue-400"></div>
                        <h3 className="text-xl font-black text-slate-900 mb-6 flex items-center gap-2">
                            <span className="material-symbols-outlined text-primary">pin_drop</span>
                            Collection Point
                        </h3>
                        <div className="rounded-3xl overflow-hidden h-64 relative border border-slate-200 bg-slate-200 flex items-center justify-center shadow-inner group">
                            <div className="absolute inset-0 bg-gradient-to-br from-slate-100 to-slate-200 opacity-60 transition-opacity duration-700 group-hover:opacity-100"></div>
                            <div className="text-center relative z-10">
                                <span className="material-symbols-outlined text-5xl text-slate-400 mb-3 drop-shadow-sm">map</span>
                                <p className="text-sm font-semibold text-slate-500 bg-white/80 backdrop-blur-sm px-4 py-2 rounded-full border border-slate-200/50">Interactive map showing Adyar, Chennai</p>
                            </div>
                            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2">
                                <div className="w-8 h-8 bg-primary/40 rounded-full animate-ping absolute -inset-1"></div>
                                <div className="w-6 h-6 bg-primary rounded-full relative border-2 border-white shadow-xl flex items-center justify-center">
                                    <span className="material-symbols-outlined text-white text-[12px] filled">{iconName}</span>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </FadeUp>

            {/* Nearby Resources */}
            <FadeUp delay={0.4} className="mt-16 mb-20">
                <div className="flex items-center justify-between mb-8">
                    <h3 className="text-2xl font-black text-slate-900 tracking-tight">Other Resources Nearby</h3>
                    <motion.button
                        onClick={() => navigate('/map')}
                        whileHover={{ x: 4 }}
                        className="text-primary font-bold text-sm bg-primary/10 px-4 py-2 rounded-lg flex items-center gap-1 transition-colors hover:bg-primary/15"
                    >
                        View all <span className="material-symbols-outlined text-sm">arrow_forward</span>
                    </motion.button>
                </div>
                <StaggerContainer staggerDelay={0.15} className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    {[
                        { icon: 'water_drop', title: 'Clean Drinking Water', distance: '500m away', bg: 'bg-blue-50 text-blue-500', color: 'text-blue-600' },
                        { icon: 'medical_services', title: 'First Aid Station', distance: '1.2km away', bg: 'bg-emerald-50 text-emerald-500', color: 'text-emerald-600' },
                        { icon: 'wifi', title: 'Satellite Internet Hub', distance: '800m away', bg: 'bg-purple-50 text-purple-500', color: 'text-purple-600' },
                    ].map((item, i) => (
                        <StaggerItem key={i}>
                            <motion.div
                                onClick={() => navigate('/map')}
                                whileHover={{ y: -6, boxShadow: '0 20px 40px -10px rgba(0,0,0,0.08)' }}
                                transition={{ duration: 0.3, ease: 'easeOut' }}
                                className="bg-white p-5 rounded-2xl border border-slate-200 cursor-pointer group flex flex-col h-full"
                            >
                                <div className={`w-full aspect-[16/10] rounded-xl ${item.bg} mb-5 flex items-center justify-center overflow-hidden transition-colors group-hover:bg-slate-50`}>
                                    <span className={`material-symbols-outlined text-5xl opacity-40 group-hover:scale-110 transition-transform duration-500 ${item.color} group-hover:opacity-100`}>{item.icon}</span>
                                </div>
                                <h4 className="text-lg font-black text-slate-900 mb-2 truncate group-hover:text-primary transition-colors">{item.title}</h4>
                                <div className="flex items-center gap-1.5 text-xs font-bold text-slate-500 mb-6 bg-slate-50 w-fit px-2 py-1 rounded border border-slate-100">
                                    <span className="material-symbols-outlined text-[14px]">location_on</span>
                                    {item.distance}
                                </div>
                                <div className="mt-auto w-full py-2.5 bg-slate-50 border border-slate-100 rounded-xl text-sm font-bold text-center text-slate-600 group-hover:bg-primary group-hover:text-white group-hover:border-primary transition-all">
                                    View Details
                                </div>
                            </motion.div>
                        </StaggerItem>
                    ))}
                </StaggerContainer>
            </FadeUp>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { resourceService } from '../services/api';
import MapContainer from '../components/Map/MapContainer';
import { motion } from 'framer-motion';

const categoryConfig = [
    { key: 'Medical Help', label: 'Medical Help', color: 'bg-rose-500', icon: 'medical_services', textColor: 'text-rose-600', hue: '#f43f5e' },
    { key: 'Shelter', label: 'Shelter', color: 'bg-blue-500', icon: 'home_work', textColor: 'text-blue-600', hue: '#3b82f6' },
    { key: 'Water & Food', label: 'Water & Food', color: 'bg-emerald-500', icon: 'water_drop', textColor: 'text-emerald-600', hue: '#10b981' },
    { key: 'Electricity / Generator', label: 'Electricity/Gen', color: 'bg-amber-500', icon: 'electric_bolt', textColor: 'text-amber-600', hue: '#f59e0b' },
    { key: 'Transport', label: 'Transport', color: 'bg-purple-500', icon: 'local_shipping', textColor: 'text-purple-600', hue: '#a855f7' },
    { key: 'Volunteers', label: 'Volunteers', color: 'bg-orange-500', icon: 'group', textColor: 'text-orange-600', hue: '#f97316' },
];

export default function ResourceMap() {
    const navigate = useNavigate();
    const [resources, setResources] = useState([]);
    const [filters, setFilters] = useState(categoryConfig.map(c => c.key));
    const [bounds, setBounds] = useState(null);
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        const fetchResources = async () => {
            setLoading(true);
            try {
                // Fetch only resources inside bounds
                const params = bounds ? bounds : {};
                const res = await resourceService.getAll(params);
                setResources(res.data);
            } catch (err) {
                console.error('Error fetching resources', err);
            } finally {
                setLoading(false);
            }
        };

        // Add a tiny debounce to prevent massive API flooding during fast panning
        const timeoutId = setTimeout(() => {
            fetchResources();
        }, 300);

        return () => clearTimeout(timeoutId);
    }, [bounds]);

    const toggleFilter = (key) => {
        setFilters(prev => prev.includes(key) ? prev.filter(f => f !== key) : [...prev, key]);
    };

    const filteredResources = resources.filter(r => filters.includes(r.category));

    const getCategoryStyle = (category) => {
        const config = categoryConfig.find(c => c.key === category);
        return config || categoryConfig[0];
    };

    return (
        <div className="flex-1 flex overflow-hidden relative h-full bg-slate-50">
            {/* Map Background Wrapper */}
            <div className="absolute inset-0 z-0">
                <MapContainer
                    resources={filteredResources}
                    onBoundsChange={setBounds}
                />

                {/* Privacy Banner */}
                <div className="absolute top-6 left-1/2 -translate-x-1/2 z-10 pointer-events-none">
                    <motion.div
                        initial={{ y: -20, opacity: 0 }}
                        animate={{ y: 0, opacity: 1 }}
                        className="bg-slate-900/90 backdrop-blur-md px-6 py-3 rounded-full shadow-2xl border border-slate-700 flex items-center gap-3"
                    >
                        {loading ? (
                            <span className="material-symbols-outlined text-slate-400 animate-spin text-sm">refresh</span>
                        ) : (
                            <span className="material-symbols-outlined text-emerald-400">satellite_alt</span>
                        )}
                        <p className="text-sm font-medium text-white shadow-sm">
                            <span className="font-bold">Live Feed:</span>
                            <span className="text-slate-300 ml-2">Displaying 1km active radius radius</span>
                        </p>
                    </motion.div>
                </div>
            </div>

            {/* Left Panel: Categories */}
            <motion.div
                initial={{ x: -20, opacity: 0 }}
                animate={{ x: 0, opacity: 1 }}
                transition={{ duration: 0.5, delay: 0.2 }}
                className="relative z-20 w-80 m-6 flex flex-col gap-4 pointer-events-none"
            >
                <div className="bg-white/95 backdrop-blur-xl rounded-3xl shadow-[0_8px_30px_rgb(0,0,0,0.12)] p-5 border border-slate-200/60 pointer-events-auto overflow-y-auto max-h-[calc(100vh-12rem)]">
                    <h3 className="text-sm font-black uppercase tracking-widest text-slate-800 mb-5 flex items-center justify-between">
                        Filters
                        <span className="text-[10px] font-black bg-primary/10 text-primary px-2.5 py-1 rounded-md">{filters.length} ACTIVE</span>
                    </h3>
                    <div className="space-y-2">
                        {categoryConfig.map(cat => (
                            <label key={cat.key} className="flex items-center justify-between p-3 rounded-2xl bg-slate-50/50 cursor-pointer border border-transparent hover:border-slate-200 transition-colors group">
                                <div className="flex items-center gap-3">
                                    <div className={`size-2.5 rounded-full ${cat.color} shadow-sm group-hover:scale-125 transition-transform`}></div>
                                    <span className="text-sm font-semibold text-slate-700">{cat.label}</span>
                                </div>
                                <input
                                    type="checkbox"
                                    checked={filters.includes(cat.key)}
                                    onChange={() => toggleFilter(cat.key)}
                                    className="rounded-md border-slate-300 text-primary focus:ring-primary/20 transition-all size-4"
                                />
                            </label>
                        ))}
                    </div>
                    <div className="mt-6 pt-5 border-t border-slate-100">
                        <motion.button
                            whileHover={{ scale: 1.02 }}
                            whileTap={{ scale: 0.98 }}
                            onClick={() => navigate('/post-resource')}
                            className="w-full py-3.5 bg-slate-900 text-white text-sm font-black rounded-2xl shadow-xl shadow-slate-900/10 flex items-center justify-center gap-2 transition-colors hover:bg-black"
                        >
                            <span className="material-symbols-outlined text-lg">add_location_alt</span>
                            Drop Resource Pin
                        </motion.button>
                    </div>
                </div>
            </motion.div>

            {/* Right Panel: Nearby Resources */}
            <motion.div
                initial={{ x: 20, opacity: 0 }}
                animate={{ x: 0, opacity: 1 }}
                transition={{ duration: 0.5, delay: 0.3 }}
                className="relative z-20 w-[400px] ml-auto m-6 flex flex-col pointer-events-none"
            >
                <div className="bg-white/95 backdrop-blur-xl rounded-3xl shadow-[0_8px_30px_rgb(0,0,0,0.12)] flex flex-col pointer-events-auto overflow-hidden border border-slate-200/60 max-h-full">
                    <div className="p-6 bg-slate-50/50 border-b border-slate-100 flex items-center justify-between backdrop-blur-md relative z-10">
                        <div>
                            <h3 className="font-black text-slate-900 text-lg tracking-tight">Active Coverage</h3>
                            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest mt-0.5">{filteredResources.length} points detected</p>
                        </div>
                        <button className="p-2.5 hover:bg-slate-200/50 rounded-xl transition-colors">
                            <span className="material-symbols-outlined text-slate-500">my_location</span>
                        </button>
                    </div>

                    <div className="flex-1 overflow-y-auto p-5 space-y-4 relative bg-slate-50/30">
                        {loading && (
                            <div className="absolute inset-0 bg-white/50 backdrop-blur-[2px] z-10 flex items-center justify-center">
                                <div className="size-8 border-[3px] border-primary/20 border-t-primary rounded-full animate-spin"></div>
                            </div>
                        )}

                        {filteredResources.length > 0 ? filteredResources.map((res, i) => {
                            const style = getCategoryStyle(res.category);
                            return (
                                <motion.div
                                    initial={{ y: 10, opacity: 0 }}
                                    animate={{ y: 0, opacity: 1 }}
                                    transition={{ delay: i * 0.05 }}
                                    key={res.id || i}
                                    onClick={() => navigate(`/resource/${res.id}`)}
                                    className="p-5 rounded-3xl border border-slate-100 bg-white hover:border-slate-300 shadow-sm hover:shadow-xl transition-all cursor-pointer group hover:-translate-y-1 ease-out duration-300"
                                >
                                    <div className="flex justify-between items-start mb-3">
                                        <div className="flex items-center gap-2">
                                            <span className={`size-6 rounded-full ${style.color}/10 flex items-center justify-center`}>
                                                <span className={`material-symbols-outlined text-[14px] ${style.textColor}`}>{style.icon}</span>
                                            </span>
                                            <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                                                {res.category}
                                            </span>
                                        </div>
                                        <div className="flex items-center gap-1 bg-slate-50 px-2 py-0.5 rounded-md border border-slate-100">
                                            <span className="material-symbols-outlined text-[10px] text-emerald-500">radar</span>
                                            <span className="text-[10px] font-black text-slate-500">LIVE</span>
                                        </div>
                                    </div>
                                    <h4 className="font-bold text-slate-900 mb-1 leading-tight group-hover:text-primary transition-colors pr-4">{res.title}</h4>
                                    <p className="text-sm text-slate-500 mb-4 line-clamp-2 leading-relaxed">{res.description}</p>
                                    <div className="flex items-center gap-3">
                                        <div className="flex-1 h-10 px-4 rounded-xl bg-slate-50 border border-slate-100 flex items-center gap-2.5">
                                            <span className="size-2.5 rounded-full bg-emerald-500 animate-pulse shadow-[0_0_8px_rgba(16,185,129,0.5)]"></span>
                                            <span className="text-[11px] font-black text-slate-600 tracking-wider font-mono">{res.status || 'AVAILABLE'}</span>
                                        </div>
                                        <button className="size-10 rounded-xl bg-primary/5 text-primary flex items-center justify-center hover:bg-primary hover:text-white transition-colors">
                                            <span className="material-symbols-outlined text-[20px]">near_me</span>
                                        </button>
                                    </div>
                                </motion.div>
                            );
                        }) : (
                            <div className="p-10 text-center flex flex-col items-center justify-center h-full text-slate-500">
                                <span className="material-symbols-outlined text-4xl mb-3 text-slate-300">location_off</span>
                                <p className="font-bold">No resources found in view</p>
                                <p className="text-sm mt-1">Try panning the map or zooming out to see more coverage areas.</p>
                            </div>
                        )}
                    </div>
                </div>
            </motion.div>
        </div>
    );
}

import { useState, useEffect } from 'react';

export default function Volunteers() {
    const [volunteers, setVolunteers] = useState([]);
    const [searchQuery, setSearchQuery] = useState('');

    useEffect(() => {
        setVolunteers([
            { id: 1, name: 'Karthik R.', role: 'Volunteer', area_code: 'CHN-ADY-01', trust_score: 92, skills: ['First Aid', 'Rescue'], status: 'Active' },
            { id: 2, name: 'Priya S.', role: 'Medical Support', area_code: 'CHN-ADY-02', trust_score: 88, skills: ['Nursing', 'CPR'], status: 'Active' },
            { id: 3, name: 'Ravi M.', role: 'Volunteer', area_code: 'CHN-ADY-01', trust_score: 75, skills: ['Transport', 'Supply Chain'], status: 'Standby' },
            { id: 4, name: 'Lakshmi D.', role: 'Volunteer', area_code: 'CHN-MYL-03', trust_score: 95, skills: ['Shelter Mgmt', 'Cooking'], status: 'Active' },
            { id: 5, name: 'Suresh K.', role: 'Medical Support', area_code: 'CHN-ADY-01', trust_score: 83, skills: ['Pharmacy', 'First Aid'], status: 'Offline' },
            { id: 6, name: 'Deepa V.', role: 'Volunteer', area_code: 'CHN-TBR-01', trust_score: 70, skills: ['Communication', 'Elderly Care'], status: 'Active' },
        ]);
    }, []);

    const filteredVolunteers = volunteers.filter(v =>
        v.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        v.skills.some(s => s.toLowerCase().includes(searchQuery.toLowerCase())) ||
        v.area_code.toLowerCase().includes(searchQuery.toLowerCase())
    );

    const statusStyle = (status) => {
        if (status === 'Active') return { color: 'text-emerald-600', bg: 'bg-emerald-50 border-emerald-200', dot: 'bg-emerald-500' };
        if (status === 'Standby') return { color: 'text-amber-600', bg: 'bg-amber-50 border-amber-200', dot: 'bg-amber-500' };
        return { color: 'text-slate-400', bg: 'bg-slate-50 border-slate-200', dot: 'bg-slate-400' };
    };

    const activeCount = volunteers.filter(v => v.status === 'Active').length;

    const avatarColors = ['bg-blue-200 text-blue-700', 'bg-rose-200 text-rose-700', 'bg-emerald-200 text-emerald-700', 'bg-purple-200 text-purple-700', 'bg-amber-200 text-amber-700', 'bg-cyan-200 text-cyan-700'];

    return (
        <div className="p-6 lg:p-10">
            <div className="max-w-7xl mx-auto">
                {/* Header */}
                <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6 mb-8">
                    <div>
                        <h2 className="text-3xl font-black tracking-tight">Volunteer Network</h2>
                        <p className="text-slate-500 mt-1">Verified community responders ready to help during emergencies.</p>
                    </div>
                    <div className="flex gap-3">
                        <div className="bg-emerald-50 border border-emerald-200 px-5 py-3 rounded-xl text-center">
                            <span className="text-2xl font-black text-emerald-700 block">{activeCount}</span>
                            <span className="text-xs font-bold text-emerald-600">Active</span>
                        </div>
                        <div className="bg-slate-50 border border-slate-200 px-5 py-3 rounded-xl text-center">
                            <span className="text-2xl font-black text-slate-900 block">{volunteers.length}</span>
                            <span className="text-xs font-bold text-slate-500">Total</span>
                        </div>
                    </div>
                </div>

                {/* Search */}
                <div className="relative mb-8 max-w-md">
                    <span className="material-symbols-outlined absolute left-4 top-1/2 -translate-y-1/2 text-slate-400">search</span>
                    <input
                        type="text"
                        placeholder="Search by name, skill, or area..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="w-full pl-12 pr-4 py-3 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-primary text-sm"
                    />
                </div>

                {/* Volunteer Grid */}
                <div className="grid md:grid-cols-2 xl:grid-cols-3 gap-5">
                    {filteredVolunteers.map((vol, i) => {
                        const ss = statusStyle(vol.status);
                        return (
                            <div key={vol.id} className="bg-white p-6 rounded-2xl border border-slate-200 hover:shadow-xl hover:-translate-y-1 transition-all group">
                                <div className="flex items-start justify-between mb-4">
                                    <div className="flex items-center gap-4">
                                        <div className={`size-14 rounded-xl ${avatarColors[i % avatarColors.length]} flex items-center justify-center text-xl font-black shadow-sm`}>
                                            {vol.name.charAt(0)}
                                        </div>
                                        <div>
                                            <h3 className="font-bold text-slate-900 text-lg leading-tight group-hover:text-primary transition-colors">{vol.name}</h3>
                                            <span className="text-sm text-slate-500">{vol.role}</span>
                                        </div>
                                    </div>
                                    <span className={`text-[10px] font-bold px-3 py-1.5 rounded-full border flex items-center gap-1.5 ${ss.bg} ${ss.color}`}>
                                        <span className={`size-2 rounded-full ${ss.dot}`}></span>
                                        {vol.status}
                                    </span>
                                </div>

                                <div className="flex items-center gap-2 text-sm text-slate-500 mb-4">
                                    <span className="material-symbols-outlined text-primary text-sm">location_on</span>
                                    <span className="font-medium">{vol.area_code}</span>
                                </div>

                                {/* Trust Score */}
                                <div className="mb-4">
                                    <div className="flex justify-between items-center mb-1">
                                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Trust Score</span>
                                        <span className="text-sm font-black">{vol.trust_score}%</span>
                                    </div>
                                    <div className="w-full h-2 bg-slate-100 rounded-full overflow-hidden">
                                        <div className="h-full bg-primary rounded-full transition-all" style={{ width: `${vol.trust_score}%` }}></div>
                                    </div>
                                </div>

                                {/* Skills */}
                                <div className="flex flex-wrap gap-2">
                                    {vol.skills.map(skill => (
                                        <span key={skill} className="bg-slate-50 text-slate-600 text-xs font-bold px-3 py-1 rounded-lg border border-slate-200">
                                            {skill}
                                        </span>
                                    ))}
                                </div>
                            </div>
                        );
                    })}
                </div>

                {filteredVolunteers.length === 0 && (
                    <div className="bg-white rounded-2xl p-16 text-center border border-slate-200 mt-8">
                        <span className="material-symbols-outlined text-5xl text-slate-300 mb-4">groups</span>
                        <h3 className="font-bold text-slate-800 text-xl">No volunteers found</h3>
                        <p className="text-slate-500 mt-2">Try a different search query or area code.</p>
                    </div>
                )}
            </div>
        </div>
    );
}
